150	pub async fn get_order(
151	    State(state): State<AppState>,
152	    AuthenticatedUser(user): AuthenticatedUser,
153	    Path(id): Path<String>,
154	) -> AppResult<Json<OrderWithItems>> {
155	    use crate::error::AppError;
156	    use shared::UserRole;
157	    let svc = StoreService::new(state.db.clone());
158	    let (order, items) = svc.get_order_with_items(&id).await?;
159	    // Object-level authorization: administrators and store managers may read any
160	    // order; all other users may only read orders they placed themselves.
161	    let role = UserRole::from_str(&user.role);
162	    let privileged = matches!(
163	        role,
164	        Some(UserRole::Administrator) | Some(UserRole::StoreManager)
165	    );
166	    if !privileged && order.user_id != user.id {
167	        return Err(AppError::Forbidden);
168	    }
169	    Ok(Json(OrderWithItems { order, items }))
170	}
