82	    pub async fn list_products(&self) -> AppResult<Vec<Product>> {
83	        let rows = sqlx::query_as::<_, Product>(
84	            "SELECT * FROM products WHERE is_active = 1 ORDER BY name",
85	        )
86	        .fetch_all(&self.db)
87	        .await?;
88	        Ok(rows)
89	    }
