91	    pub async fn create_product(
92	        &self,
93	        input: CreateProductInput,
94	        actor_id: &str,
95	    ) -> AppResult<Product> {
96	        if input.name.trim().is_empty() {
97	            return Err(AppError::Validation("product name required".into()));
98	        }
99	        if input.price < 0.0 {
100	            return Err(AppError::Validation("price must be ≥ 0".into()));
101	        }
102	        let id = Uuid::new_v4().to_string();
103	        let now = Utc::now().to_rfc3339();
104	        sqlx::query(
105	            "INSERT INTO products (id, name, description, price, stock_quantity, is_active, created_by, created_at)
106	             VALUES (?, ?, ?, ?, ?, 1, ?, ?)",
107	        )
108	        .bind(&id)
109	        .bind(&input.name)
110	        .bind(&input.description)
111	        .bind(input.price)
112	        .bind(input.stock_quantity)
113	        .bind(actor_id)
114	        .bind(&now)
115	        .execute(&self.db)
116	        .await?;
117	        let row = sqlx::query_as::<_, Product>("SELECT * FROM products WHERE id = ?")
118	            .bind(&id)
119	            .fetch_one(&self.db)
120	            .await?;
121	        Ok(row)
122	    }
