124	    pub async fn list_promotions(&self) -> AppResult<Vec<Promotion>> {
125	        let rows = sqlx::query_as::<_, Promotion>(
126	            "SELECT * FROM promotions ORDER BY priority DESC, created_at DESC",
127	        )
128	        .fetch_all(&self.db)
129	        .await?;
130	        Ok(rows)
131	    }
