133	    pub async fn create_promotion(
134	        &self,
135	        input: CreatePromotionInput,
136	        actor_id: &str,
137	    ) -> AppResult<Promotion> {
138	        if input.name.trim().is_empty() {
139	            return Err(AppError::Validation("promotion name required".into()));
140	        }
141	        if !["percent", "fixed"].contains(&input.discount_type.as_str()) {
142	            return Err(AppError::Validation(
143	                "discount_type must be 'percent' or 'fixed'".into(),
144	            ));
145	        }
146	        if input.discount_value < 0.0 {
147	            return Err(AppError::Validation("discount_value must be ≥ 0".into()));
148	        }
149	        let from = DateTime::parse_from_rfc3339(&input.effective_from)
150	            .map_err(|e| AppError::Validation(format!("effective_from: {e}")))?;
151	        let until = DateTime::parse_from_rfc3339(&input.effective_until)
152	            .map_err(|e| AppError::Validation(format!("effective_until: {e}")))?;
153	        if from >= until {
154	            return Err(AppError::Validation(
155	                "effective_from must be strictly before effective_until".into(),
156	            ));
157	        }
158	        let id = Uuid::new_v4().to_string();
159	        let now = Utc::now().to_rfc3339();
160	        sqlx::query(
161	            "INSERT INTO promotions (id, name, description, discount_value, discount_type, effective_from, effective_until, mutual_exclusion_group, priority, is_active, created_by, created_at)
162	             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?)",
163	        )
164	        .bind(&id)
165	        .bind(&input.name)
166	        .bind(&input.description)
167	        .bind(input.discount_value)
168	        .bind(&input.discount_type)
169	        .bind(&input.effective_from)
170	        .bind(&input.effective_until)
171	        .bind(&input.mutual_exclusion_group)
172	        .bind(input.priority)
173	        .bind(actor_id)
174	        .bind(&now)
175	        .execute(&self.db)
176	        .await?;
177	        let row = sqlx::query_as::<_, Promotion>("SELECT * FROM promotions WHERE id = ?")
178	            .bind(&id)
179	            .fetch_one(&self.db)
180	            .await?;
181	        Ok(row)
182	    }
