192	    /// Run a cart through the promotion engine and persist the resulting order
193	    /// + per-line trace.
194	    pub async fn create_order(
195	        &self,
196	        user_id: &str,
197	        cart: Vec<CartItem>,
198	    ) -> AppResult<(Order, CheckoutResult)> {
199	        if cart.is_empty() {
200	            return Err(AppError::Validation("cart is empty".into()));
201	        }
202	        let promos = self.list_promotions().await?;
203	        let result = apply_best_promotion(&cart, &promos);
204	
205	        let order_id = Uuid::new_v4().to_string();
206	        let now = Utc::now().to_rfc3339();
207	        let mut tx = self.db.begin().await?;
208	        sqlx::query(
209	            "INSERT INTO orders (id, user_id, status, subtotal, discount_applied, total, created_at)
210	             VALUES (?, ?, 'completed', ?, ?, ?, ?)",
211	        )
212	        .bind(&order_id)
213	        .bind(user_id)
214	        .bind(result.subtotal)
215	        .bind(result.total_discount)
216	        .bind(result.total)
217	        .bind(&now)
218	        .execute(&mut *tx)
219	        .await?;
220	        for line in &result.line_items {
221	            let item_id = Uuid::new_v4().to_string();
222	            let trace_json = serde_json::to_string(line).unwrap_or_else(|_| "{}".into());
223	            sqlx::query(
224	                "INSERT INTO order_items
225	                 (id, order_id, product_id, product_name, quantity, unit_price, discount_amount, promotion_applied, promotion_trace)
226	                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
227	            )
228	            .bind(&item_id)
229	            .bind(&order_id)
230	            .bind(&line.item.product_id)
231	            .bind(&line.item.product_name)
232	            .bind(line.item.quantity)
233	            .bind(line.item.unit_price)
234	            .bind(line.discount_amount)
235	            .bind(&line.promotion_applied)
236	            .bind(&trace_json)
237	            .execute(&mut *tx)
238	            .await?;
239	        }
240	        tx.commit().await?;
241	
242	        let order = sqlx::query_as::<_, Order>("SELECT * FROM orders WHERE id = ?")
243	            .bind(&order_id)
244	            .fetch_one(&self.db)
245	            .await?;
246	        Ok((order, result))
247	    }
