249	    pub async fn list_orders(&self, user_id: Option<&str>, limit: i64) -> AppResult<Vec<Order>> {
250	        let rows = if let Some(u) = user_id {
251	            sqlx::query_as::<_, Order>(
252	                "SELECT * FROM orders WHERE user_id = ? ORDER BY created_at DESC LIMIT ?",
253	            )
254	            .bind(u)
255	            .bind(limit)
256	            .fetch_all(&self.db)
257	            .await?
258	        } else {
259	            sqlx::query_as::<_, Order>("SELECT * FROM orders ORDER BY created_at DESC LIMIT ?")
260	                .bind(limit)
