281	// ─── Pure promotion-engine functions — no DB access — easy to unit-test ───
282	
283	/// Select and apply the best eligible promotion at checkout.
284	/// Step 1: Filter by effective time window.
285	/// Step 2: Within each mutual_exclusion_group, keep only highest-priority promotion.
286	/// Step 3: Apply the promotion producing the greatest total discount.
287	/// Returns per-line-item traceable discount details.
288	pub fn apply_best_promotion(cart: &[CartItem], promotions: &[Promotion]) -> CheckoutResult {
289	    let now = Utc::now();
290	
291	    let eligible: Vec<&Promotion> = promotions
292	        .iter()
293	        .filter(|p| p.is_active == 1 && in_window(p, now))
294	        .collect();
295	
296	    let resolved = resolve_exclusion_groups(&eligible);
297	
298	    let best = resolved
299	        .iter()
300	        .copied()
301	        .max_by(|a, b| {
302	            let da = total_cart_discount(cart, a);
303	            let db = total_cart_discount(cart, b);
304	            da.partial_cmp(&db).unwrap_or(Ordering::Equal)
305	        });
306	
307	    let subtotal: f64 = cart
308	        .iter()
309	        .map(|i| i.unit_price * i.quantity as f64)
310	        .sum();
311	    let best_total = best.map(|p| total_cart_discount(cart, p)).unwrap_or(0.0);
312	
313	    let line_items: Vec<LineItemResult> = cart
314	        .iter()
315	        .map(|item| {
316	            let line_subtotal = item.unit_price * item.quantity as f64;
317	            let discount = if subtotal > 0.0 {
318	                (line_subtotal / subtotal) * best_total
319	            } else {
320	                0.0
321	            };
322	            LineItemResult {
323	                item: item.clone(),
324	                line_subtotal,
325	                discount_amount: discount,
326	                line_total: line_subtotal - discount,
327	                promotion_applied: best.map(|p| p.name.clone()),
328	            }
329	        })
330	        .collect();
331	
332	    CheckoutResult {
333	        line_items,
334	        subtotal,
335	        total_discount: best_total,
336	        total: subtotal - best_total,
337	        best_promotion: best.cloned(),
338	    }
339	}
340	
341	/// Within each mutual_exclusion_group keep only the highest-priority promotion.
342	/// Promotions with `mutual_exclusion_group = None` always survive.
343	pub fn resolve_exclusion_groups<'a>(eligible: &[&'a Promotion]) -> Vec<&'a Promotion> {
344	    let mut by_group: HashMap<String, &Promotion> = HashMap::new();
345	    let mut ungrouped: Vec<&Promotion> = Vec::new();
346	    for p in eligible {
347	        match &p.mutual_exclusion_group {
348	            Some(g) if !g.is_empty() => {
349	                let entry = by_group.entry(g.clone()).or_insert(*p);
350	                if p.priority > entry.priority {
351	                    *entry = *p;
352	                }
353	            }
354	            _ => ungrouped.push(*p),
355	        }
356	    }
357	    let mut out: Vec<&Promotion> = by_group.into_values().collect();
358	    out.extend(ungrouped);
359	    out
360	}
361	
362	/// Total discount that the given promotion would apply to the entire cart.
363	pub fn total_cart_discount(cart: &[CartItem], p: &Promotion) -> f64 {
364	    let subtotal: f64 = cart
365	        .iter()
366	        .map(|i| i.unit_price * i.quantity as f64)
367	        .sum();
368	    match p.discount_type.as_str() {
369	        "percent" => subtotal * (p.discount_value / 100.0),
370	        "fixed" => p.discount_value.min(subtotal),
371	        _ => 0.0,
372	    }
373	}
374	
375	/// Check whether `now` lies inside the promotion's effective window.
376	pub fn in_window(p: &Promotion, now: DateTime<Utc>) -> bool {
377	    let from = DateTime::parse_from_rfc3339(&p.effective_from);
378	    let until = DateTime::parse_from_rfc3339(&p.effective_until);
379	    matches!(
380	        (from, until),
381	        (Ok(f), Ok(u)) if f.with_timezone(&Utc) <= now && now <= u.with_timezone(&Utc)
382	    )
383	}
