1	//! Authentication service: login, logout, lockout, attempt tracking.
2	//!
3	//! Owns every read and write against the `users`, `login_attempts`, and
4	//! `sessions` tables. The lockout policy from CLAUDE.md (5 failed attempts in a
5	//! 15-minute sliding window — checked against both username AND client IP) lives
6	//! in `check_lockout` below.
7	
8	use chrono::{DateTime, Duration, Utc};
9	use sqlx::SqlitePool;
10	use uuid::Uuid;
11	
12	use crate::error::{AppError, AppResult};
13	use crate::models::user::User;
14	use crate::security::{csrf, password};
15	
16	/// How long an issued session cookie remains valid before requiring a fresh login.
17	pub const SESSION_TTL_HOURS: i64 = 8;
18	
19	/// Authentication service. Constructed once and shared via the application state.
20	#[derive(Clone)]
21	pub struct AuthService {
22	    pub db: SqlitePool,
23	}
24	
25	/// Result of a successful `login()` call: the user record, the new session id
26	/// (set as the `sv_session` cookie), and the matching CSRF token.
27	pub struct LoginOutcome {
28	    pub user: User,
29	    pub session_id: String,
30	    pub csrf_token: String,
31	}
32	
33	impl AuthService {
34	    pub fn new(db: SqlitePool) -> Self {
35	        Self { db }
36	    }
37	
38	    /// Check and enforce account lockout: 5 failed attempts within a 15-minute
39	    /// sliding window. The lockout expires automatically when the window passes.
40	    /// Checks both username-based AND IP-based attempt counts.
41	    pub async fn check_lockout(&self, username: &str, ip: &str) -> AppResult<()> {
42	        let window_start = (Utc::now() - Duration::minutes(15)).to_rfc3339();
43	        let count: i64 = sqlx::query_scalar(
44	            "SELECT COUNT(*) FROM login_attempts
45	             WHERE (username = ? OR ip_address = ?)
46	             AND attempted_at > ?
47	             AND success = 0",
48	        )
49	        .bind(username)
50	        .bind(ip)
51	        .bind(&window_start)
52	        .fetch_one(&self.db)
53	        .await?;
54	
55	        if count >= 5 {
56	            return Err(AppError::AccountLocked {
57	                message: "Too many failed login attempts. Try again in 15 minutes.".to_string(),
58	            });
59	        }
60	        Ok(())
61	    }
