63	    /// Persist a single login attempt for the lockout sliding window.
64	    pub async fn record_attempt(&self, username: &str, ip: &str, success: bool) -> AppResult<()> {
65	        let id = Uuid::new_v4().to_string();
66	        let now = Utc::now().to_rfc3339();
67	        sqlx::query(
68	            "INSERT INTO login_attempts (id, username, ip_address, attempted_at, success)
69	             VALUES (?, ?, ?, ?, ?)",
70	        )
71	        .bind(&id)
72	        .bind(username)
73	        .bind(ip)
74	        .bind(&now)
75	        .bind(if success { 1 } else { 0 })
76	        .execute(&self.db)
77	        .await?;
78	        Ok(())
79	    }
80	
81	    /// Authenticate a username/password pair, enforcing the lockout policy
82	    /// before doing any password work, and create a session+CSRF token on success.
83	    pub async fn login(
84	        &self,
85	        username: &str,
86	        password_plain: &str,
87	        ip: &str,
88	        user_agent: Option<&str>,
89	    ) -> AppResult<LoginOutcome> {
90	        // 1. Lockout gate — runs before we touch the password hasher.
91	        self.check_lockout(username, ip).await?;
92	
93	        // 2. Look up the user.
94	        let user: Option<User> =
95	            sqlx::query_as::<_, User>("SELECT * FROM users WHERE username = ? AND is_active = 1")
96	                .bind(username)
97	                .fetch_optional(&self.db)
98	                .await?;
99	
100	        let user = match user {
101	            Some(u) => u,
102	            None => {
103	                self.record_attempt(username, ip, false).await?;
104	                return Err(AppError::Auth);
105	            }
106	        };
107	
108	        // 3. Verify the password.
109	        let valid = password::verify_password(password_plain, &user.password_hash)?;
110	        if !valid {
111	            self.record_attempt(username, ip, false).await?;
112	            return Err(AppError::Auth);
113	        }
114	
115	        // 4. Record success and mint a session.
116	        self.record_attempt(username, ip, true).await?;
117	
118	        let session_id = Uuid::new_v4().to_string();
119	        let csrf_token = csrf::generate_token();
120	        let expires_at = (Utc::now() + Duration::hours(SESSION_TTL_HOURS)).to_rfc3339();
121	        let now = Utc::now().to_rfc3339();
122	
123	        sqlx::query(
124	            "INSERT INTO sessions (id, user_id, csrf_token, ip_address, user_agent, expires_at, created_at)
125	             VALUES (?, ?, ?, ?, ?, ?, ?)",
126	        )
127	        .bind(&session_id)
128	        .bind(&user.id)
129	        .bind(&csrf_token)
130	        .bind(ip)
131	        .bind(user_agent)
132	        .bind(&expires_at)
133	        .bind(&now)
134	        .execute(&self.db)
135	        .await?;
136	
137	        Ok(LoginOutcome {
138	            user,
139	            session_id,
140	            csrf_token,
141	        })
142	    }
