144	    /// Drop a session row by id. Idempotent — succeeds even if the session was
145	    /// already gone.
146	    pub async fn logout(&self, session_id: &str) -> AppResult<()> {
147	        sqlx::query("DELETE FROM sessions WHERE id = ?")
148	            .bind(session_id)
149	            .execute(&self.db)
150	            .await?;
