161	    /// Create a new user. Hashes the password with Argon2id before storing.
162	    /// Sensitive PII (`phone`, `national_id`) — when provided — is encrypted
163	    /// with AES-256-GCM via `security::encryption::encrypt_field` BEFORE it
164	    /// ever reaches SQLite, so the raw database row only ever holds ciphertext.
165	    #[allow(clippy::too_many_arguments)]
166	    pub async fn create_user(
167	        &self,
168	        username: &str,
169	        password_plain: &str,
170	        role: &str,
171	        full_name: Option<&str>,
172	        email: Option<&str>,
173	        phone: Option<&str>,
174	        national_id: Option<&str>,
175	        encryption_key: &[u8; 32],
176	    ) -> AppResult<User> {
177	        if username.trim().is_empty() || password_plain.is_empty() {
178	            return Err(AppError::Validation("username + password required".into()));
179	        }
180	        if shared::UserRole::from_str(role).is_none() {
181	            return Err(AppError::Validation(format!("unknown role: {role}")));
182	        }
183	        let id = format!("u-{}", Uuid::new_v4());
184	        let now = Utc::now().to_rfc3339();
185	        let hash = password::hash_password(password_plain)?;
186	        let phone_ct = match phone {
187	            Some(p) if !p.is_empty() => Some(crate::security::encryption::encrypt_field(
188	                p,
189	                encryption_key,
190	            )?),
191	            _ => None,
192	        };
193	        let national_id_ct = match national_id {
194	            Some(n) if !n.is_empty() => Some(crate::security::encryption::encrypt_field(
195	                n,
196	                encryption_key,
197	            )?),
198	            _ => None,
199	        };
200	        sqlx::query(
201	            "INSERT INTO users (id, username, password_hash, role, is_active, full_name, email, phone_encrypted, national_id_encrypted, created_at, updated_at) VALUES (?, ?, ?, ?, 1, ?, ?, ?, ?, ?, ?)",
202	        )
203	        .bind(&id)
204	        .bind(username)
205	        .bind(&hash)
206	        .bind(role)
207	        .bind(full_name)
208	        .bind(email)
209	        .bind(phone_ct.as_deref())
210	        .bind(national_id_ct.as_deref())
211	        .bind(&now)
212	        .bind(&now)
213	        .execute(&self.db)
214	        .await?;
215	        let row = sqlx::query_as::<_, User>("SELECT * FROM users WHERE id = ?")
216	            .bind(&id)
217	            .fetch_one(&self.db)
218	            .await?;
219	        Ok(row)
220	    }
