251	    /// Returns the current user paired with their CSRF token if the session id
252	    /// is valid and unexpired.
253	    pub async fn get_session_user(&self, session_id: &str) -> AppResult<Option<(User, String)>> {
254	        #[derive(sqlx::FromRow)]
255	        struct Row {
256	            user_id: String,
257	            csrf_token: String,
258	            expires_at: String,
259	        }
260	        let row: Option<Row> = sqlx::query_as::<_, Row>(
261	            "SELECT user_id, csrf_token, expires_at FROM sessions WHERE id = ?",
262	        )
263	        .bind(session_id)
264	        .fetch_optional(&self.db)
265	        .await?;
266	
267	        let Some(row) = row else { return Ok(None) };
268	        if let Ok(exp) = DateTime::parse_from_rfc3339(&row.expires_at) {
269	            if exp.with_timezone(&Utc) < Utc::now() {
270	                self.logout(session_id).await?;
271	                return Ok(None);
272	            }
273	        }
274	
275	        let user: Option<User> =
276	            sqlx::query_as::<_, User>("SELECT * FROM users WHERE id = ? AND is_active = 1")
277	                .bind(&row.user_id)
278	                .fetch_optional(&self.db)
279	                .await?;
280	        Ok(user.map(|u| (u, row.csrf_token)))
281	    }
282	}
