73	    pub async fn get_member_metrics(&self) -> AppResult<MemberMetrics> {
74	        let series = sqlx::query_as::<_, MemberSnapshot>(
75	            "SELECT * FROM member_snapshots ORDER BY snapshot_date DESC LIMIT 12",
76	        )
