90	    /// Churn rate = `churned / prior_period_total` expressed as a percentage.
91	    /// If there is only one snapshot it returns 0% (no prior period to compare).
92	    pub async fn get_churn_rate(&self) -> AppResult<ChurnRate> {
93	        let snaps = sqlx::query_as::<_, MemberSnapshot>(
94	            "SELECT * FROM member_snapshots ORDER BY snapshot_date DESC LIMIT 2",
95	        )
96	        .fetch_all(&self.db)
97	        .await?;
98	        if snaps.len() < 2 {
99	            return Ok(ChurnRate {
100	                rate_pct: 0.0,
101	                from: snaps.first().map(|s| s.snapshot_date.clone()).unwrap_or_default(),
102	                to: snaps.first().map(|s| s.snapshot_date.clone()).unwrap_or_default(),
103	            });
104	        }
105	        let latest = &snaps[0];
106	        let prior = &snaps[1];
107	        let rate = if prior.total_members > 0 {
108	            (latest.churned_members as f64 / prior.total_members as f64) * 100.0
109	        } else {
110	            0.0
111	        };
112	        Ok(ChurnRate {
113	            rate_pct: rate,
114	            from: prior.snapshot_date.clone(),
115	            to: latest.snapshot_date.clone(),
116	        })
117	    }
