134	    /// Fund summary with optional structured filters. `period` is the legacy
135	    /// budget-period string; `date_from`/`date_to`/`category`/`role` narrow
136	    /// further. All are `None` by default so existing callers see no change.
137	    pub async fn get_fund_summary(
138	        &self,
139	        period: Option<&str>,
140	        date_from: Option<&str>,
141	        date_to: Option<&str>,
142	        category: Option<&str>,
143	        role: Option<&str>,
144	    ) -> AppResult<FundSummary> {
145	        let mut q = String::from("SELECT * FROM fund_transactions WHERE 1=1");
146	        let mut binds: Vec<String> = Vec::new();
147	        if let Some(p) = period {
148	            q.push_str(" AND budget_period = ?");
149	            binds.push(p.to_string());
150	        }
151	        if let Some(d) = date_from {
152	            q.push_str(" AND created_at >= ?");
153	            binds.push(d.to_string());
154	        }
155	        if let Some(d) = date_to {
156	            q.push_str(" AND created_at <= ?");
157	            binds.push(d.to_string());
158	        }
159	        if let Some(c) = category {
160	            q.push_str(" AND category = ?");
161	            binds.push(c.to_string());
162	        }
163	        if let Some(r) = role {
164	            // Filter by the role of the user who recorded the transaction.
165	            // The `recorded_by` column holds a user id; we join against users
166	            // to match on role. Using a subquery keeps the dynamic SQL simple.
167	            q.push_str(
168	                " AND recorded_by IN (SELECT id FROM users WHERE role = ?)",
169	            );
170	            binds.push(r.to_string());
171	        }
172	        q.push_str(" ORDER BY created_at DESC LIMIT 200");
173	        let mut query = sqlx::query_as::<_, FundTransaction>(&q);
174	        for b in &binds {
175	            query = query.bind(b);
176	        }
177	        let transactions = query.fetch_all(&self.db).await?;
178	        let total_income: f64 = transactions
179	            .iter()
180	            .filter(|t| t.r#type == "income")
181	            .map(|t| t.amount)
182	            .sum();
183	        let total_expense: f64 = transactions
184	            .iter()
185	            .filter(|t| t.r#type == "expense")
186	            .map(|t| t.amount)
187	            .sum();
188	        let net = total_income - total_expense;
189	        let over_budget = total_expense > FUND_BUDGET_CAP;
190	        Ok(FundSummary {
191	            total_income,
192	            total_expense,
193	            net,
194	            budget_cap: FUND_BUDGET_CAP,
195	            over_budget,
196	            period: period.unwrap_or("all").to_string(),
197	            transactions,
198	        })
199	    }
