201	    pub async fn get_approval_cycle_stats(&self) -> AppResult<ApprovalStats> {
202	        let rows = sqlx::query_as::<_, ApprovalCycleRecord>(
203	            "SELECT * FROM approval_cycle_records WHERE cycle_time_minutes IS NOT NULL ORDER BY cycle_time_minutes DESC",
204	        )
205	        .fetch_all(&self.db)
206	        .await?;
207	        let count = rows.len() as i64;
208	        let mins: Vec<i64> = rows.iter().filter_map(|r| r.cycle_time_minutes).collect();
209	        let sum: i64 = mins.iter().sum();
210	        let avg = if !mins.is_empty() {
211	            sum as f64 / mins.len() as f64
212	        } else {
213	            0.0
214	        };
215	        let median = if !mins.is_empty() {
216	            let mut sorted = mins.clone();
217	            sorted.sort();
218	            sorted[sorted.len() / 2] as f64
219	        } else {
220	            0.0
221	        };
222	        let slowest = rows.iter().take(5).cloned().collect();
223	        Ok(ApprovalStats {
224	            count,
225	            avg_minutes: avg,
226	            median_minutes: median,
227	            slowest,
228	        })
229	    }
