302	    /// Render a real PDF via the `printpdf` crate.
303	    ///
304	    /// All async data fetching happens **before** the `PdfDocument` is created.
305	    /// `printpdf::PdfDocumentReference` wraps an `Rc<RefCell<…>>` that is not
306	    /// `Send`, so it must never be held across an `.await` point — otherwise
307	    /// the resulting future cannot be used as an axum handler.
308	    pub async fn generate_pdf(
309	        &self,
310	        report_type: &str,
311	        period: Option<&str>,
312	    ) -> AppResult<Vec<u8>> {
313	        // Step 1 — collect text via async DB queries (no PDF objects yet).
314	        let title = format!("ScholarVault — {} report", report_type);
315	        let generated_at = format!("Generated {}", Utc::now().to_rfc3339());
316	        let lines: Vec<String> = match report_type {
317	            "fund" => {
318	                let summary = self.get_fund_summary(period, None, None, None, None).await?;
319	                let mut v = vec![
320	                    format!("Total income:  ${:.2}", summary.total_income),
321	                    format!("Total expense: ${:.2}", summary.total_expense),
322	                    format!("Net:           ${:.2}", summary.net),
323	                    format!(
324	                        "Budget cap:    ${:.2} ({})",
325	                        summary.budget_cap,
326	                        if summary.over_budget { "OVER" } else { "ok" }
327	                    ),
328	                    String::new(),
329	                    "Transactions:".into(),
330	                ];
331	                for t in summary.transactions.iter().take(20) {
332	                    v.push(format!(
333	                        "  {} ${:.2} {} - {}",
334	                        t.r#type, t.amount, t.category, t.description
335	                    ));
336	                }
337	                v
338	            }
339	            "members" => {
340	                let m = self.get_member_metrics().await?;
341	                let mut v = vec![
342	                    format!("Current members: {}", m.current_total),
343	                    format!("New (window):    {}", m.new_members),
344	                    format!("Churned:         {}", m.churned),
345	                    String::new(),
346	                    "Snapshots:".into(),
347	                ];
348	                for s in m.series.iter().take(12) {
349	                    v.push(format!(
350	                        "  {}: total={} new={} churned={}",
351	                        s.snapshot_date, s.total_members, s.new_members, s.churned_members
352	                    ));
353	                }
354	                v
355	            }
356	            other => return Err(AppError::Validation(format!("unknown report type: {other}"))),
357	        };
358	
359	        // Step 2 — synchronously build the PDF. `Send`-only types live here.
360	        Self::render_pdf(&title, &generated_at, &lines)
361	    }
362	
363	    fn render_pdf(title: &str, generated_at: &str, lines: &[String]) -> AppResult<Vec<u8>> {
364	        use printpdf::*;
365	        let (doc, page1, layer1) =
366	            PdfDocument::new("ScholarVault Report", Mm(210.0), Mm(297.0), "Layer 1");
367	        let font = doc
368	            .add_builtin_font(BuiltinFont::Helvetica)
369	            .map_err(|e| AppError::Internal(format!("pdf font: {e}")))?;
370	        let current_layer = doc.get_page(page1).get_layer(layer1);
371	        current_layer.use_text(title, 18.0, Mm(20.0), Mm(270.0), &font);
372	        current_layer.use_text(generated_at, 10.0, Mm(20.0), Mm(260.0), &font);
373	
374	        let mut y: f32 = 240.0;
375	        for line in lines {
376	            current_layer.use_text(line, 11.0, Mm(20.0), Mm(y), &font);
377	            y -= 6.0;
378	            if y < 20.0 {
379	                break;
380	            }
381	        }
382	
383	        let mut buf: Vec<u8> = Vec::new();
384	        {
385	            let mut writer = std::io::BufWriter::new(&mut buf);
386	            doc.save(&mut writer)
387	                .map_err(|e| AppError::Internal(format!("pdf save: {e}")))?;
388	        }
389	        Ok(buf)
390	    }
391	
392	    /// Schedule a report for generation. The current implementation runs the
393	    /// generation **inline** so the workflow is deterministic for tests, but
394	    /// the public surface matches the SPEC: status flips from `pending` to
395	    /// `complete`, the file lands on disk, and a single-use `download_token`
396	    /// is issued.
397	    pub async fn schedule_report(
398	        &self,
399	        report_type: &str,
400	        format: &str,
401	        period: Option<&str>,
402	        actor_id: &str,
403	    ) -> AppResult<ScheduledReport> {
404	        let id = Uuid::new_v4().to_string();
405	        let now = Utc::now().to_rfc3339();
406	        sqlx::query(
407	            "INSERT INTO scheduled_reports (id, report_type, filters, status, created_by, created_at) VALUES (?, ?, ?, 'pending', ?, ?)",
408	        )
409	        .bind(&id)
410	        .bind(report_type)
411	        .bind(serde_json::json!({"format": format, "period": period}).to_string())
412	        .bind(actor_id)
413	        .bind(&now)
414	        .execute(&self.db)
415	        .await?;
416	
417	        let bytes = match format {
418	            "csv" => self.generate_csv(report_type, period).await?,
419	            "pdf" => self.generate_pdf(report_type, period).await?,
420	            other => return Err(AppError::Validation(format!("unknown format: {other}"))),
421	        };
422	        std::fs::create_dir_all(&self.reports_dir).ok();
423	        let extension = if format == "pdf" { "pdf" } else { "csv" };
424	        let path = self.reports_dir.join(format!("{}.{}", id, extension));
425	        std::fs::write(&path, &bytes)?;
426	
427	        let token = Uuid::new_v4().to_string();
428	        let completed = Utc::now().to_rfc3339();
429	        sqlx::query(
430	            "UPDATE scheduled_reports SET status='complete', file_path = ?, download_token = ?, completed_at = ? WHERE id = ?",
431	        )
432	        .bind(path.to_string_lossy().to_string())
433	        .bind(&token)
434	        .bind(&completed)
435	        .bind(&id)
436	        .execute(&self.db)
437	        .await?;
438	
439	        let row = sqlx::query_as::<_, ScheduledReport>(
440	            "SELECT * FROM scheduled_reports WHERE id = ?",
441	        )
442	        .bind(&id)
443	        .fetch_one(&self.db)
444	        .await?;
445	        Ok(row)
446	    }
447	
448	    pub async fn list_reports(&self, user_id: &str) -> AppResult<Vec<ScheduledReport>> {
449	        let rows = sqlx::query_as::<_, ScheduledReport>(
450	            "SELECT * FROM scheduled_reports WHERE created_by = ? ORDER BY created_at DESC LIMIT 100",
451	        )
452	        .bind(user_id)
453	        .fetch_all(&self.db)
454	        .await?;
455	        Ok(rows)
456	    }
457	
458	    /// Download a completed report by id + token. The token is **single-use**:
459	    /// after a successful read it is cleared from the row so the same URL
460	    /// cannot be reused.
461	    /// Download a completed report. The caller must be authenticated; ownership
462	    /// is verified here at the data layer so an attacker in possession of a
463	    /// token alone cannot fetch another user's report. Administrators bypass
464	    /// the ownership check.
465	    pub async fn download_report(
466	        &self,
467	        report_id: &str,
468	        token: &str,
469	        requesting_user_id: &str,
470	        is_admin: bool,
471	    ) -> AppResult<(String, Vec<u8>)> {
472	        let row: Option<ScheduledReport> = sqlx::query_as::<_, ScheduledReport>(
473	            "SELECT * FROM scheduled_reports WHERE id = ?",
474	        )
475	        .bind(report_id)
476	        .fetch_optional(&self.db)
477	        .await?;
478	        let row = row.ok_or(AppError::NotFound)?;
479	        if !is_admin && row.created_by != requesting_user_id {
480	            return Err(AppError::Forbidden);
481	        }
482	        if row.status != "complete" {
483	            return Err(AppError::Conflict("report not yet complete".into()));
484	        }
485	        let stored_token = row.download_token.as_deref().unwrap_or("");
486	        if stored_token.is_empty() || stored_token != token {
487	            return Err(AppError::NotFound);
488	        }
489	        let path = row.file_path.as_deref().ok_or(AppError::NotFound)?;
490	        let bytes = std::fs::read(path)?;
491	        // Single-use: clear the token so the same URL cannot be reused.
492	        sqlx::query("UPDATE scheduled_reports SET download_token = NULL WHERE id = ?")
493	            .bind(report_id)
494	            .execute(&self.db)
495	            .await?;
496	        let mime = if path.ends_with(".pdf") {
497	            "application/pdf".to_string()
498	        } else {
499	            "text/csv".to_string()
500	        };
501	        Ok((mime, bytes))
502	    }
503	}
