1	//! Side-by-side compare-two-outcomes view. Calls
2	//! `/api/outcomes/:id/compare/:other_id` and highlights fields that differ.
3	
4	use leptos::*;
5	use wasm_bindgen_futures::spawn_local;
6	
7	use crate::api::outcomes::{self as out_api, CompareResult};
8	
9	#[component]
10	pub fn CompareOutcomes() -> impl IntoView {
11	    let (id_a, set_id_a) = create_signal(String::new());
12	    let (id_b, set_id_b) = create_signal(String::new());
13	    let (result, set_result) = create_signal::<Option<CompareResult>>(None);
14	    let (status, set_status) = create_signal::<Option<String>>(None);
15	
16	    let load = move |_| {
17	        let a = id_a.get();
18	        let b = id_b.get();
19	        if a.is_empty() || b.is_empty() {
20	            set_status.set(Some("Provide both ids".into()));
21	            return;
22	        }
23	        spawn_local(async move {
24	            match out_api::compare_outcomes(&a, &b).await {
25	                Ok(r) => {
26	                    set_result.set(Some(r));
27	                    set_status.set(Some("Loaded".into()));
28	                }
29	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
30	            }
31	        });
32	    };
33	
34	    view! {
35	        <div>
36	            <div class="sv-card" style="margin-bottom:16px;">
37	                <div style="display:grid;grid-template-columns:1fr 1fr auto;gap:10px;align-items:end;">
38	                    <div>
39	                        <label class="sv-label">"Outcome A id"</label>
40	                        <input class="sv-input" prop:value=move || id_a.get()
41	                            on:input=move |ev| set_id_a.set(event_target_value(&ev))/>
42	                    </div>
43	                    <div>
44	                        <label class="sv-label">"Outcome B id"</label>
45	                        <input class="sv-input" prop:value=move || id_b.get()
46	                            on:input=move |ev| set_id_b.set(event_target_value(&ev))/>
47	                    </div>
48	                    <button class="sv-btn-primary" on:click=load>"Compare"</button>
49	                </div>
50	                {move || status.get().map(|s| view! {
51	                    <div style="margin-top:10px;font-size:11px;color:#A0A0B0;">{s}</div>
52	                })}
53	            </div>
54	
55	            {move || result.get().map(|r| {
56	                let title_diff = r.a.title != r.b.title;
57	                let abstract_diff = r.a.abstract_snippet != r.b.abstract_snippet;
58	                let cert_diff = r.a.certificate_number != r.b.certificate_number;
59	                let r_a = r.a.clone();
60	                let r_b = r.b.clone();
61	                view! {
62	                    <div style="display:grid;grid-template-columns:1fr 1fr;gap:24px;">
63	                        {render_card("A", r_a, title_diff, abstract_diff, cert_diff)}
64	                        {render_card("B", r_b, title_diff, abstract_diff, cert_diff)}
65	                    </div>
66	                    <div class="sv-card" style="margin-top:18px;background:rgba(245,197,24,0.05);">
67	                        <div style="font-size:13px;color:#F5C518;font-weight:600;">
68	                            {format!("Similarity → title {:.2}, abstract {:.2}", r.title_similarity, r.abstract_similarity)}
69	                        </div>
70	                    </div>
71	                }
72	            })}
73	        </div>
74	    }
75	}
76	
77	fn render_card(
78	    label: &'static str,
79	    o: out_api::Outcome,
80	    title_diff: bool,
81	    abstract_diff: bool,
82	    cert_diff: bool,
83	) -> impl IntoView {
84	    let highlight = |diff: bool| if diff { "background:rgba(245,158,11,0.10);padding:8px;border-radius:4px;" } else { "padding:8px;" };
85	    view! {
86	        <div class="sv-card">
87	            <h3 style="margin:0 0 12px;font-size:14px;color:#F5C518;">{format!("Outcome {}", label)}</h3>
88	            <div style="font-size:11px;color:#A0A0B0;font-family:monospace;">{o.id.clone()}</div>
89	            <div style="margin-top:12px;">
90	                <label class="sv-label">"Type"</label>
91	                <div style="font-size:13px;">{o.r#type.clone()}</div>
92	            </div>
93	            <div style="margin-top:8px;">
94	                <label class="sv-label">"Title"</label>
95	                <div style=highlight(title_diff)>{o.title.clone()}</div>
96	            </div>
97	            <div style="margin-top:8px;">
98	                <label class="sv-label">"Abstract"</label>
99	                <div style=highlight(abstract_diff)>{o.abstract_snippet.clone()}</div>
100	            </div>
101	            <div style="margin-top:8px;">
102	                <label class="sv-label">"Certificate"</label>
103	                <div style=highlight(cert_diff)>{o.certificate_number.clone().unwrap_or_else(|| "—".into())}</div>
104	            </div>
105	        </div>
106	    }
107	}
