1	//! Multi-step register-outcome form: type → details → contributors → submit.
2	//! Step 2 also surfaces duplicate-detection candidates from the create endpoint.
3	
4	use leptos::*;
5	use wasm_bindgen_futures::spawn_local;
6	
7	use crate::api::outcomes::{
8	    self as out_api, AddContributorInput, CreateOutcomeInput, DuplicateCandidate,
9	};
10	use crate::logic::validation::{share_total_color, share_total_state, ShareTotalState};
11	
12	#[derive(Clone, Copy, PartialEq, Eq)]
13	enum Step {
14	    Type,
15	    Details,
16	    Contributors,
17	    Done,
18	}
19	
20	#[component]
21	pub fn RegisterOutcome() -> impl IntoView {
22	    let (step, set_step) = create_signal(Step::Type);
23	    let (otype, set_otype) = create_signal::<String>("paper".to_string());
24	    let (title, set_title) = create_signal(String::new());
25	    let (abstract_text, set_abstract) = create_signal(String::new());
26	    let (cert, set_cert) = create_signal(String::new());
27	
28	    let (created_id, set_created_id) = create_signal::<Option<String>>(None);
29	    let (duplicates, set_duplicates) = create_signal::<Vec<DuplicateCandidate>>(Vec::new());
30	    let (status, set_status) = create_signal::<Option<String>>(None);
31	
32	    let (contributors, set_contributors) = create_signal::<Vec<(String, i64)>>(Vec::new());
33	    let (new_contrib_user, set_new_contrib_user) = create_signal::<String>("u-reviewer".into());
34	    let (new_contrib_share, set_new_contrib_share) = create_signal::<i64>(100);
35	    // (filename, file_size_bytes) — simple tuple so the signal type compiles
36	    // on both WASM and native targets (the actual upload only runs in-browser).
37	    let (evidence_files, set_evidence_files) = create_signal::<Vec<(String, i64)>>(Vec::new());
38	
39	    let create_action = move |_| {
40	        let payload = CreateOutcomeInput {
41	            r#type: otype.get(),
42	            title: title.get(),
43	            abstract_snippet: abstract_text.get(),
44	            certificate_number: if cert.get().is_empty() { None } else { Some(cert.get()) },
45	        };
46	        spawn_local(async move {
47	            match out_api::create_outcome(payload).await {
48	                Ok(res) => {
49	                    set_created_id.set(Some(res.outcome.id.clone()));
50	                    set_duplicates.set(res.duplicate_candidates);
51	                    set_step.set(Step::Contributors);
52	                    set_status.set(Some(format!("Outcome draft created: {}", res.outcome.id)));
53	                }
54	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
55	            }
56	        });
57	    };
58	
59	    let add_contributor = move |_| {
60	        let id = match created_id.get() {
61	            Some(v) => v,
62	            None => {
63	                set_status.set(Some("Create the outcome first".into()));
64	                return;
65	            }
66	        };
67	        let user = new_contrib_user.get();
68	        let share = new_contrib_share.get();
69	        spawn_local(async move {
70	            let res = out_api::add_contributor(
71	                &id,
72	                AddContributorInput {
73	                    user_id: user.clone(),
74	                    share_percentage: share,
75	                    role_in_work: None,
76	                },
77	            )
78	            .await;
79	            match res {
80	                Ok(_) => {
81	                    set_contributors.update(|v| v.push((user, share)));
82	                    set_status.set(Some("Contributor added".into()));
83	                }
84	                Err(e) => set_status.set(Some(format!("Rejected: {}", e.message))),
85	            }
86	        });
87	    };
88	
89	    let submit_action = move |_| {
90	        let id = match created_id.get() {
91	            Some(v) => v,
92	            None => return,
93	        };
94	        spawn_local(async move {
95	            match out_api::submit_outcome(&id).await {
96	                Ok(_) => {
97	                    set_status.set(Some("Submitted for review".into()));
98	                    set_step.set(Step::Done);
99	                }
100	                Err(e) => set_status.set(Some(format!("Submit failed: {}", e.message))),
101	            }
102	        });
103	    };
104	
105	    view! {
106	        <div style="display:grid;grid-template-columns:1fr 320px;gap:24px;">
107	            <div class="sv-card">
108	                {move || match step.get() {
109	                    Step::Type => view! {
110	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 1 — Type"</h2>
111	                        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
112	                            {type_card("paper", "Research Paper", "Peer-reviewed publication", otype, set_otype)}
113	                            {type_card("patent", "Patent", "Filed or granted patent", otype, set_otype)}
114	                            {type_card("competition_result", "Competition Result", "Award or placement", otype, set_otype)}
115	                            {type_card("software_copyright", "Software Copyright", "Registered software work", otype, set_otype)}
116	                        </div>
117	                        <button class="sv-btn-primary" style="margin-top:24px;" on:click=move |_| set_step.set(Step::Details)>
118	                            "Next →"
119	                        </button>
120	                    }.into_view(),
121	                    Step::Details => view! {
122	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 2 — Details"</h2>
123	                        <label class="sv-label">"Title"</label>
124	                        <input class="sv-input" prop:value=move || title.get()
125	                            on:input=move |ev| set_title.set(event_target_value(&ev))/>
126	                        <label class="sv-label" style="margin-top:14px;">"Abstract / description"</label>
127	                        <textarea class="sv-input" rows="4" prop:value=move || abstract_text.get()
128	                            on:input=move |ev| set_abstract.set(event_target_value(&ev))></textarea>
129	                        <label class="sv-label" style="margin-top:14px;">"Certificate number (optional)"</label>
130	                        <input class="sv-input" prop:value=move || cert.get()
131	                            on:input=move |ev| set_cert.set(event_target_value(&ev))/>
132	                        <div style="display:flex;gap:8px;margin-top:24px;">
133	                            <button class="sv-btn-secondary" on:click=move |_| set_step.set(Step::Type)>"← Back"</button>
134	                            <button class="sv-btn-primary" on:click=create_action>"Create draft & check duplicates →"</button>
135	                        </div>
136	                    }.into_view(),
137	                    Step::Contributors => view! {
138	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 3 — Contributors"</h2>
139	                        {move || {
140	                            let dups = duplicates.get();
141	                            if dups.is_empty() { ().into_view() } else {
142	                                view! {
143	                                    <div class="sv-card" style="background:rgba(245,158,11,0.10);border-color:rgba(245,158,11,0.40);margin-bottom:16px;">
144	                                        <div style="font-size:12px;color:#F59E0B;font-weight:600;margin-bottom:6px;">
145	                                            {format!("⚠ {} similar outcome(s) found", dups.len())}
146	                                        </div>
147	                                        {dups.into_iter().take(5).map(|d| view! {
148	                                            <div style="font-size:12px;color:#A0A0B0;">
149	                                                {format!("• {} ({}, score {:.2})", d.title, d.reason, d.similarity_score)}
150	                                            </div>
151	                                        }).collect_view()}
152	                                    </div>
153	                                }.into_view()
154	                            }
155	                        }}
156	                        <div style="display:grid;grid-template-columns:1fr 100px auto;gap:8px;align-items:end;">
157	                            <div>
158	                                <label class="sv-label">"User id"</label>
159	                                <input class="sv-input" prop:value=move || new_contrib_user.get()
160	                                    on:input=move |ev| set_new_contrib_user.set(event_target_value(&ev))/>
161	                            </div>
162	                            <div>
163	                                <label class="sv-label">"Share %"</label>
164	                                <input class="sv-input" type="number" min="1" max="100"
165	                                    prop:value=move || new_contrib_share.get().to_string()
166	                                    on:input=move |ev| set_new_contrib_share.set(event_target_value(&ev).parse().unwrap_or(0))/>
167	                            </div>
168	                            <button class="sv-btn-secondary" on:click=add_contributor>"Add"</button>
169	                        </div>
170	
171	                        <div style="margin-top:18px;">
172	                            <table class="sv-table">
173	                                <thead><tr><th>"User"</th><th>"Share"</th></tr></thead>
174	                                <tbody>
175	                                    {move || contributors.get().into_iter().map(|(u, s)| view! {
176	                                        <tr><td>{u}</td><td>{format!("{}%", s)}</td></tr>
177	                                    }).collect_view()}
178	                                </tbody>
179	                            </table>
180	                        </div>
181	
182	                        {move || {
183	                            let shares: Vec<i64> = contributors.get().iter().map(|(_, s)| *s).collect();
184	                            let total: i64 = shares.iter().sum();
185	                            let state = share_total_state(&shares);
186	                            let label = match state {
187	                                ShareTotalState::Complete => "Ready to submit (100%)",
188	                                ShareTotalState::Under => "Under-allocated",
189	                                ShareTotalState::Over => "Over-allocated",
190	                            };
191	                            view! {
192	                                <div style=move || format!("margin-top:14px;padding:10px 14px;border-radius:6px;font-size:12px;font-weight:600;color:{};background:rgba(255,255,255,0.04);", share_total_color(&shares))>
193	                                    {format!("{} — total {}%", label, total)}
194	                                </div>
195	                            }
196	                        }}
197	
198	                        // ── Evidence upload ──
199	                        <div style="margin-top:24px;border-top:1px solid rgba(245,197,24,0.10);padding-top:16px;">
200	                            <h3 style="margin:0 0 8px;font-size:13px;color:#F5C518;">"Evidence files (PDF/JPG/PNG)"</h3>
201	                            <input
202	                                type="file"
203	                                accept=".pdf,.jpg,.jpeg,.png"
204	                                class="sv-input"
205	                                style="padding:6px;"
206	                                on:change=move |ev| {
207	                                    use wasm_bindgen::JsCast;
208	                                    let input: web_sys::HtmlInputElement =
209	                                        ev.target().unwrap().unchecked_into();
210	                                    if let Some(files) = input.files() {
211	                                        if let Some(file) = files.get(0) {
212	                                            let oid = match created_id.get() {
213	                                                Some(v) => v,
214	                                                None => {
215	                                                    set_status.set(Some("Create outcome first".into()));
216	                                                    return;
217	                                                }
218	                                            };
219	                                            #[cfg(target_arch = "wasm32")]
220	                                {
221	                                    spawn_local(async move {
222	                                        match out_api::upload_evidence(&oid, file).await {
223	                                            Ok(ef) => {
224	                                                set_evidence_files.update(|v| v.push((ef.filename, ef.file_size)));
225	                                                set_status.set(Some("Evidence uploaded".into()));
226	                                            }
227	                                            Err(e) => set_status.set(Some(format!("Upload error: {}", e.message))),
228	                                        }
229	                                    });
230	                                }
231	                                #[cfg(not(target_arch = "wasm32"))]
232	                                {
233	                                    let _ = (oid, file, set_evidence_files);
234	                                    set_status.set(Some("Upload only available in browser".into()));
235	                                }
236	                                        }
237	                                    }
238	                                }
239	                            />
240	                            {move || {
241	                                let files = evidence_files.get();
242	                                if files.is_empty() { ().into_view() } else {
243	                                    view! {
244	                                        <div style="margin-top:8px;font-size:11px;color:#A0A0B0;">
245	                                            {files.into_iter().map(|(name, size)| view! {
246	                                                <div>{format!("✓ {} ({} KB)", name, size / 1024)}</div>
247	                                            }).collect_view()}
248	                                        </div>
249	                                    }.into_view()
250	                                }
251	                            }}
252	                        </div>
253	
254	                        <div style="display:flex;gap:8px;margin-top:24px;">
255	                            <button class="sv-btn-secondary" on:click=move |_| set_step.set(Step::Details)>"← Back"</button>
256	                            <button class="sv-btn-primary" on:click=submit_action>"Submit for review"</button>
257	                        </div>
