1	//! Backend unit tests for the promotion engine.
2	
3	use backend::models::store::Promotion;
4	use backend::services::store_service::{
5	    apply_best_promotion, in_window, resolve_exclusion_groups, total_cart_discount, CartItem,
6	};
7	use chrono::{Duration, Utc};
8	
9	fn promo(
10	    id: &str,
11	    name: &str,
12	    discount_value: f64,
13	    discount_type: &str,
14	    group: Option<&str>,
15	    priority: i64,
16	) -> Promotion {
17	    let now = Utc::now();
18	    Promotion {
19	        id: id.into(),
20	        name: name.into(),
21	        description: String::new(),
22	        discount_value,
23	        discount_type: discount_type.into(),
24	        effective_from: (now - Duration::days(1)).to_rfc3339(),
25	        effective_until: (now + Duration::days(7)).to_rfc3339(),
26	        mutual_exclusion_group: group.map(|s| s.to_string()),
27	        priority,
28	        is_active: 1,
29	        created_by: "test".into(),
30	        created_at: now.to_rfc3339(),
31	    }
32	}
33	
34	fn cart() -> Vec<CartItem> {
35	    vec![
36	        CartItem {
37	            product_id: "p1".into(),
38	            product_name: "Book".into(),
39	            quantity: 2,
40	            unit_price: 50.0,
41	        },
42	        CartItem {
43	            product_id: "p2".into(),
44	            product_name: "Kit".into(),
45	            quantity: 1,
46	            unit_price: 30.0,
47	        },
48	    ]
49	}
50	
51	#[test]
52	fn test_best_offer_selects_highest_priority_in_group() {
53	    // Two promos in the same group with different priorities — only the
54	    // higher-priority promo survives mutual-exclusion resolution.
55	    let p_low = promo("p-low", "10% off", 10.0, "percent", Some("site"), 1);
56	    let p_high = promo("p-high", "15% off", 15.0, "percent", Some("site"), 5);
57	    let resolved = resolve_exclusion_groups(&[&p_low, &p_high]);
58	    assert_eq!(resolved.len(), 1);
59	    assert_eq!(resolved[0].id, "p-high");
60	}
61	
62	#[test]
63	fn test_mutual_exclusion_one_per_group() {
64	    let p_a1 = promo("a1", "5% A", 5.0, "percent", Some("group-a"), 1);
65	    let p_a2 = promo("a2", "10% A", 10.0, "percent", Some("group-a"), 9);
66	    let p_b1 = promo("b1", "$5 B", 5.0, "fixed", Some("group-b"), 2);
67	    let resolved = resolve_exclusion_groups(&[&p_a1, &p_a2, &p_b1]);
68	    assert_eq!(resolved.len(), 2);
69	    let ids: Vec<&str> = resolved.iter().map(|p| p.id.as_str()).collect();
70	    assert!(ids.contains(&"a2"));
71	    assert!(ids.contains(&"b1"));
72	    assert!(!ids.contains(&"a1"));
73	}
74	
75	#[test]
76	fn test_two_exclusion_groups_each_gets_best() {
77	    // Across the surviving set, apply_best_promotion picks the single best.
78	    let p_a = promo("a", "20% A", 20.0, "percent", Some("group-a"), 9);
79	    let p_b = promo("b", "$5 B", 5.0, "fixed", Some("group-b"), 9);
80	    let result = apply_best_promotion(&cart(), &[p_a.clone(), p_b]);
81	    // Cart subtotal = 130.0; 20% = 26.0 > $5 fixed
82	    assert_eq!(result.best_promotion.unwrap().id, "a");
83	    assert!((result.total_discount - 26.0).abs() < 1e-6);
84	}
85	
86	#[test]
87	fn test_expired_promotion_not_applied() {
88	    let now = Utc::now();
89	    let mut p = promo("expired", "50% off", 50.0, "percent", None, 9);
90	    p.effective_from = (now - Duration::days(30)).to_rfc3339();
91	    p.effective_until = (now - Duration::days(1)).to_rfc3339();
92	    assert!(!in_window(&p, Utc::now()));
93	    let result = apply_best_promotion(&cart(), &[p]);
94	    assert!(result.best_promotion.is_none());
95	}
96	
97	#[test]
98	fn test_future_promotion_not_applied() {
99	    let now = Utc::now();
100	    let mut p = promo("future", "50% off", 50.0, "percent", None, 9);
101	    p.effective_from = (now + Duration::days(1)).to_rfc3339();
102	    p.effective_until = (now + Duration::days(10)).to_rfc3339();
103	    assert!(!in_window(&p, Utc::now()));
104	    let result = apply_best_promotion(&cart(), &[p]);
105	    assert_eq!(result.total_discount, 0.0);
106	}
107	
108	#[test]
109	fn test_promotion_at_boundary_applied() {
110	    // A promo whose effective_from is exactly now should be in-window.
111	    let now = Utc::now();
112	    let mut p = promo("boundary", "5% off", 5.0, "percent", None, 1);
113	    p.effective_from = (now - Duration::seconds(1)).to_rfc3339();
114	    p.effective_until = (now + Duration::seconds(1)).to_rfc3339();
115	    assert!(in_window(&p, Utc::now()));
116	}
117	
118	#[test]
119	fn test_line_item_trace_contains_promotion_name() {
120	    let p = promo("named", "Spring Sale", 10.0, "percent", None, 1);
121	    let result = apply_best_promotion(&cart(), &[p]);
122	    assert!(result.line_items.iter().all(|l| {
123	        l.promotion_applied
124	            .as_deref()
125	            .map(|n| n == "Spring Sale")
126	            .unwrap_or(false)
127	    }));
128	}
129	
130	#[test]
131	fn test_total_cart_discount_percent() {
132	    let p = promo("p10", "10%", 10.0, "percent", None, 0);
133	    let total = total_cart_discount(&cart(), &p); // 130 * 0.10 = 13
134	    assert!((total - 13.0).abs() < 1e-9);
135	}
136	
137	#[test]
138	fn test_total_cart_discount_fixed() {
139	    let p = promo("p5", "$5 off", 5.0, "fixed", None, 0);
140	    let total = total_cart_discount(&cart(), &p);
141	    assert_eq!(total, 5.0);
142	}
143	
