10	async fn login_as(app: axum::Router, user: &str, pw: &str) -> (String, String) {
11	    let req = Request::builder()
12	        .method(Method::POST)
13	        .uri("/api/auth/login")
14	        .header("content-type", "application/json")
15	        .body(Body::from(
16	            json!({"username": user, "password": pw}).to_string(),
17	        ))
18	        .unwrap();
19	    let resp = app.oneshot(req).await.unwrap();
20	    assert_eq!(resp.status(), StatusCode::OK);
21	    let mut session = String::new();
22	    let mut csrf = String::new();
23	    for h in resp.headers().get_all("set-cookie").iter() {
24	        let v = h.to_str().unwrap_or("");
25	        if let Some(rest) = v.strip_prefix("sv_session=") {
26	            session = format!("sv_session={}", rest.split(';').next().unwrap());
27	        }
28	        if let Some(rest) = v.strip_prefix("csrf_token=") {
29	            csrf = rest.split(';').next().unwrap().to_string();
30	        }
31	    }
32	    (session, csrf)
33	}
