148	        .method(Method::POST)
149	        .uri("/api/auth/login")
150	        .header("content-type", "application/json")
151	        .body(Body::from(
152	            json!({"username":"admin","password":"ScholarAdmin2024!"}).to_string(),
153	        ))
154	        .unwrap();
155	    let resp = app.clone().oneshot(req).await.unwrap();
156	    assert_eq!(resp.status(), StatusCode::OK);
157	    let mut session = String::new();
158	    let mut csrf = String::new();
159	    for h in resp.headers().get_all("set-cookie").iter() {
160	        let v = h.to_str().unwrap_or("");
161	        if let Some(rest) = v.strip_prefix("sv_session=") {
162	            session = format!("sv_session={}", rest.split(';').next().unwrap());
163	        }
164	        if let Some(rest) = v.strip_prefix("csrf_token=") {
165	            csrf = rest.split(';').next().unwrap().to_string();
166	        }
167	    }
168	
169	    let phone = "5551234567";
170	    let national_id = "A9876543210";
171	    let payload = json!({
172	        "username":"pii-user",
173	        "password":"Scholar2024!",
174	        "role":"content_curator",
175	        "phone": phone,
176	        "national_id": national_id
177	    })
178	    .to_string();
179	    let req = Request::builder()
180	        .method(Method::POST)
181	        .uri("/api/admin/users")
182	        .header("content-type", "application/json")
183	        .header("cookie", format!("{}; csrf_token={}", session, csrf))
184	        .header("X-CSRF-Token", csrf)
185	        .body(Body::from(payload))
186	        .unwrap();
187	    let resp = app.oneshot(req).await.unwrap();
188	    assert_eq!(resp.status(), StatusCode::OK);
189	    let bytes = to_bytes(resp.into_body(), 64 * 1024).await.unwrap();
190	    let body: serde_json::Value = serde_json::from_slice(&bytes).unwrap();
191	    let body_text = body.to_string();
192	
193	    // Masked presentation only — plaintext must NOT appear anywhere in the
194	    // response envelope.
195	    assert!(!body_text.contains(phone), "phone plaintext leaked in response");
196	    assert!(
197	        !body_text.contains(national_id),
198	        "national_id plaintext leaked in response"
199	    );
200	    assert_eq!(body["phone_masked"], "******4567");
201	    assert_eq!(body["national_id_masked"], "*******3210");
202	
203	    // DB row must contain ciphertext, not plaintext.
204	    let row: (Option<String>, Option<String>) = sqlx::query_as(
205	        "SELECT phone_encrypted, national_id_encrypted FROM users WHERE username = 'pii-user'",
206	    )
207	    .fetch_one(&state.db)
208	    .await
209	    .unwrap();
210	    let phone_ct = row.0.expect("phone_encrypted must be populated");
211	    let nid_ct = row.1.expect("national_id_encrypted must be populated");
212	    assert_ne!(phone_ct, phone, "stored phone must not be plaintext");
213	    assert_ne!(nid_ct, national_id, "stored national_id must not be plaintext");
214	    // AES-256-GCM + 12-byte nonce + base64 → at least ~24 chars even for a
215	    // short plaintext. Sanity check that we're storing an encrypted blob.
216	    assert!(phone_ct.len() > phone.len() + 8);
217	    assert!(nid_ct.len() > national_id.len() + 8);
218	}
