293	    let (session, csrf) = login_as_admin(app.clone()).await;
294	
295	    // Hit an admin-only path with a bogus id to provoke an internal lookup
296	    // path; most responses will already be generic, but we additionally force
297	    // a raw Database error by requesting report download with a garbage token.
298	    let req = Request::builder()
