235	pub async fn upload_evidence(
236	    State(state): State<AppState>,
237	    RequireReviewer(user): RequireReviewer,
238	    Path(outcome_id): Path<String>,
239	    mut multipart: Multipart,
240	) -> AppResult<Json<EvidenceFile>> {
241	    let svc = OutcomeService::new(state.db.clone());
242	    require_outcome_creator(&svc, &outcome_id, &user.id, &user.role).await?;
243	    let mut bytes_field: Option<Vec<u8>> = None;
244	    let mut filename = String::from("upload.bin");
245	    let mut declared_mime = String::from("application/octet-stream");
246	
247	    while let Some(field) = multipart
248	        .next_field()
249	        .await
250	        .map_err(|e| AppError::Validation(format!("multipart: {e}")))?
251	    {
252	        let name = field.name().unwrap_or("").to_string();
253	        if name == "file" {
254	            if let Some(fname) = field.file_name() {
255	                filename = fname.to_string();
256	            }
257	            if let Some(ct) = field.content_type() {
258	                declared_mime = ct.to_string();
259	            }
260	            let data = field
261	                .bytes()
262	                .await
263	                .map_err(|e| AppError::Validation(format!("multipart bytes: {e}")))?;
264	            bytes_field = Some(data.to_vec());
265	        }
266	    }
267	    let bytes = bytes_field.ok_or_else(|| AppError::Validation("missing 'file' field".into()))?;
268	
269	    let file_svc = FileService::new(
270	        state.db.clone(),
271	        *state.encryption_key,
272	        (*state.evidence_dir).clone(),
273	    );
274	    let row = file_svc
275	        .upload_evidence(&outcome_id, &bytes, &filename, &declared_mime, &user.id)
276	        .await?;
277	    AuditService::new(state.db.clone())
278	        .log(
279	            &user.id,
280	            AuditAction::UploadEvidence,
281	            "evidence_file",
282	            Some(&row.id),
283	            None,
284	            Some(AuditService::compute_hash(&row.sha256_fingerprint)),
285	            None,
286	        )
287	        .await?;
288	    Ok(Json(row))
289	}
