1	//! Multi-step register-outcome form: type → details → contributors → submit.
2	//! Step 2 also surfaces duplicate-detection candidates from the create endpoint.
3	
4	use leptos::*;
5	use wasm_bindgen_futures::spawn_local;
6	
7	use crate::api::outcomes::{
8	    self as out_api, AddContributorInput, CreateOutcomeInput, DuplicateCandidate,
9	};
10	use crate::logic::validation::{share_total_color, share_total_state, ShareTotalState};
11	
12	#[derive(Clone, Copy, PartialEq, Eq)]
13	enum Step {
14	    Type,
15	    Details,
16	    Contributors,
17	    Done,
18	}
19	
20	#[component]
21	pub fn RegisterOutcome() -> impl IntoView {
22	    let (step, set_step) = create_signal(Step::Type);
23	    let (otype, set_otype) = create_signal::<String>("paper".to_string());
24	    let (title, set_title) = create_signal(String::new());
25	    let (abstract_text, set_abstract) = create_signal(String::new());
26	    let (cert, set_cert) = create_signal(String::new());
27	
28	    let (created_id, set_created_id) = create_signal::<Option<String>>(None);
29	    let (duplicates, set_duplicates) = create_signal::<Vec<DuplicateCandidate>>(Vec::new());
30	    let (status, set_status) = create_signal::<Option<String>>(None);
31	
32	    let (contributors, set_contributors) = create_signal::<Vec<(String, i64)>>(Vec::new());
33	    let (new_contrib_user, set_new_contrib_user) = create_signal::<String>("u-reviewer".into());
34	    let (new_contrib_share, set_new_contrib_share) = create_signal::<i64>(100);
35	    // (filename, file_size_bytes) — simple tuple so the signal type compiles
36	    // on both WASM and native targets (the actual upload only runs in-browser).
37	    let (evidence_files, set_evidence_files) = create_signal::<Vec<(String, i64)>>(Vec::new());
38	    // Duplicate-gating: user must acknowledge/compare duplicates before submit.
39	    let (dup_acknowledged, set_dup_acknowledged) = create_signal(false);
40	
41	    let create_action = move |_| {
42	        let payload = CreateOutcomeInput {
43	            r#type: otype.get(),
44	            title: title.get(),
45	            abstract_snippet: abstract_text.get(),
46	            certificate_number: if cert.get().is_empty() { None } else { Some(cert.get()) },
47	        };
48	        spawn_local(async move {
49	            match out_api::create_outcome(payload).await {
50	                Ok(res) => {
51	                    set_created_id.set(Some(res.outcome.id.clone()));
52	                    set_duplicates.set(res.duplicate_candidates);
53	                    set_step.set(Step::Contributors);
54	                    set_status.set(Some(format!("Outcome draft created: {}", res.outcome.id)));
55	                }
56	                Err(e) => set_status.set(Some(format!("Error: {}", e.message))),
57	            }
58	        });
59	    };
60	
61	    let add_contributor = move |_| {
62	        let id = match created_id.get() {
63	            Some(v) => v,
64	            None => {
65	                set_status.set(Some("Create the outcome first".into()));
66	                return;
67	            }
68	        };
69	        let user = new_contrib_user.get();
70	        let share = new_contrib_share.get();
71	        spawn_local(async move {
72	            let res = out_api::add_contributor(
73	                &id,
74	                AddContributorInput {
75	                    user_id: user.clone(),
76	                    share_percentage: share,
77	                    role_in_work: None,
78	                },
79	            )
80	            .await;
81	            match res {
82	                Ok(_) => {
83	                    set_contributors.update(|v| v.push((user, share)));
84	                    set_status.set(Some("Contributor added".into()));
85	                }
86	                Err(e) => set_status.set(Some(format!("Rejected: {}", e.message))),
87	            }
88	        });
89	    };
90	
91	    let submit_action = move |_| {
92	        let id = match created_id.get() {
93	            Some(v) => v,
94	            None => return,
95	        };
96	        spawn_local(async move {
97	            match out_api::submit_outcome(&id).await {
98	                Ok(_) => {
99	                    set_status.set(Some("Submitted for review".into()));
100	                    set_step.set(Step::Done);
101	                }
102	                Err(e) => set_status.set(Some(format!("Submit failed: {}", e.message))),
103	            }
104	        });
105	    };
106	
107	    view! {
108	        <div style="display:grid;grid-template-columns:1fr 320px;gap:24px;">
109	            <div class="sv-card">
110	                {move || match step.get() {
111	                    Step::Type => view! {
112	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 1 — Type"</h2>
113	                        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
114	                            {type_card("paper", "Research Paper", "Peer-reviewed publication", otype, set_otype)}
115	                            {type_card("patent", "Patent", "Filed or granted patent", otype, set_otype)}
116	                            {type_card("competition_result", "Competition Result", "Award or placement", otype, set_otype)}
117	                            {type_card("software_copyright", "Software Copyright", "Registered software work", otype, set_otype)}
118	                        </div>
119	                        <button class="sv-btn-primary" style="margin-top:24px;" on:click=move |_| set_step.set(Step::Details)>
120	                            "Next →"
121	                        </button>
122	                    }.into_view(),
123	                    Step::Details => view! {
124	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 2 — Details"</h2>
125	                        <label class="sv-label">"Title"</label>
126	                        <input class="sv-input" prop:value=move || title.get()
127	                            on:input=move |ev| set_title.set(event_target_value(&ev))/>
128	                        <label class="sv-label" style="margin-top:14px;">"Abstract / description"</label>
129	                        <textarea class="sv-input" rows="4" prop:value=move || abstract_text.get()
130	                            on:input=move |ev| set_abstract.set(event_target_value(&ev))></textarea>
131	                        <label class="sv-label" style="margin-top:14px;">"Certificate number (optional)"</label>
132	                        <input class="sv-input" prop:value=move || cert.get()
133	                            on:input=move |ev| set_cert.set(event_target_value(&ev))/>
134	                        <div style="display:flex;gap:8px;margin-top:24px;">
135	                            <button class="sv-btn-secondary" on:click=move |_| set_step.set(Step::Type)>"← Back"</button>
136	                            <button class="sv-btn-primary" on:click=create_action>"Create draft & check duplicates →"</button>
137	                        </div>
138	                    }.into_view(),
139	                    Step::Contributors => view! {
140	                        <h2 style="margin:0 0 16px;font-size:18px;color:#F5C518;">"Step 3 — Contributors"</h2>
141	                        {move || {
142	                            let dups = duplicates.get();
143	                            if dups.is_empty() {
144	                                // No duplicates — auto-acknowledge so submit is enabled.
145	                                set_dup_acknowledged.set(true);
146	                                ().into_view()
147	                            } else {
148	                                let current_id = created_id.get().unwrap_or_default();
149	                                view! {
150	                                    <div class="sv-card" style="background:rgba(245,158,11,0.10);border-color:rgba(245,158,11,0.40);margin-bottom:16px;">
151	                                        <div style="font-size:12px;color:#F59E0B;font-weight:600;margin-bottom:6px;">
152	                                            {format!("⚠ {} similar outcome(s) found — review before submitting", dups.len())}
153	                                        </div>
154	                                        {dups.into_iter().take(5).map(|d| {
155	                                            let compare_href = format!("#/outcomes/compare/{}/{}", current_id, d.id);
156	                                            view! {
157	                                                <div style="display:flex;justify-content:space-between;align-items:center;font-size:12px;color:#A0A0B0;padding:4px 0;">
158	                                                    <span>{format!("• {} ({}, score {:.2})", d.title, d.reason, d.similarity_score)}</span>
159	                                                    <a href=compare_href target="_blank"
160	                                                       class="sv-btn-secondary" style="font-size:10px;padding:3px 8px;">
161	                                                        "Compare"
162	                                                    </a>
163	                                                </div>
164	                                            }
165	                                        }).collect_view()}
166	                                        <div style="margin-top:10px;border-top:1px solid rgba(245,158,11,0.20);padding-top:10px;">
167	                                            <label style="display:flex;align-items:center;gap:8px;font-size:12px;color:#F59E0B;cursor:pointer;">
168	                                                <input type="checkbox"
169	                                                    prop:checked=move || dup_acknowledged.get()
170	                                                    on:change=move |ev| {
171	                                                        let checked = event_target_checked(&ev);
172	                                                        set_dup_acknowledged.set(checked);
173	                                                    }/>
174	                                                "I have reviewed the duplicates and confirm this is a new outcome"
175	                                            </label>
176	                                        </div>
177	                                    </div>
178	                                }.into_view()
179	                            }
180	                        }}
181	                        <div style="display:grid;grid-template-columns:1fr 100px auto;gap:8px;align-items:end;">
182	                            <div>
183	                                <label class="sv-label">"User id"</label>
184	                                <input class="sv-input" prop:value=move || new_contrib_user.get()
185	                                    on:input=move |ev| set_new_contrib_user.set(event_target_value(&ev))/>
186	                            </div>
187	                            <div>
188	                                <label class="sv-label">"Share %"</label>
189	                                <input class="sv-input" type="number" min="1" max="100"
190	                                    prop:value=move || new_contrib_share.get().to_string()
191	                                    on:input=move |ev| set_new_contrib_share.set(event_target_value(&ev).parse().unwrap_or(0))/>
192	                            </div>
193	                            <button class="sv-btn-secondary" on:click=add_contributor>"Add"</button>
194	                        </div>
195	
196	                        <div style="margin-top:18px;">
197	                            <table class="sv-table">
198	                                <thead><tr><th>"User"</th><th>"Share"</th></tr></thead>
199	                                <tbody>
200	                                    {move || contributors.get().into_iter().map(|(u, s)| view! {
201	                                        <tr><td>{u}</td><td>{format!("{}%", s)}</td></tr>
202	                                    }).collect_view()}
203	                                </tbody>
204	                            </table>
205	                        </div>
206	
207	                        {move || {
208	                            let shares: Vec<i64> = contributors.get().iter().map(|(_, s)| *s).collect();
209	                            let total: i64 = shares.iter().sum();
210	                            let state = share_total_state(&shares);
211	                            let label = match state {
212	                                ShareTotalState::Complete => "Ready to submit (100%)",
213	                                ShareTotalState::Under => "Under-allocated",
214	                                ShareTotalState::Over => "Over-allocated",
215	                            };
216	                            view! {
217	                                <div style=move || format!("margin-top:14px;padding:10px 14px;border-radius:6px;font-size:12px;font-weight:600;color:{};background:rgba(255,255,255,0.04);", share_total_color(&shares))>
218	                                    {format!("{} — total {}%", label, total)}
219	                                </div>
220	                            }
221	                        }}
222	
223	                        // ── Evidence upload ──
224	                        <div style="margin-top:24px;border-top:1px solid rgba(245,197,24,0.10);padding-top:16px;">
225	                            <h3 style="margin:0 0 8px;font-size:13px;color:#F5C518;">"Evidence files (PDF/JPG/PNG)"</h3>
226	                            <input
227	                                type="file"
228	                                accept=".pdf,.jpg,.jpeg,.png"
229	                                class="sv-input"
230	                                style="padding:6px;"
231	                                on:change=move |ev| {
232	                                    use wasm_bindgen::JsCast;
233	                                    let input: web_sys::HtmlInputElement =
234	                                        ev.target().unwrap().unchecked_into();
235	                                    if let Some(files) = input.files() {
236	                                        if let Some(file) = files.get(0) {
237	                                            let oid = match created_id.get() {
238	                                                Some(v) => v,
239	                                                None => {
240	                                                    set_status.set(Some("Create outcome first".into()));
241	                                                    return;
242	                                                }
243	                                            };
244	                                            #[cfg(target_arch = "wasm32")]
245	                                {
246	                                    spawn_local(async move {
247	                                        match out_api::upload_evidence(&oid, file).await {
248	                                            Ok(ef) => {
249	                                                set_evidence_files.update(|v| v.push((ef.filename, ef.file_size)));
250	                                                set_status.set(Some("Evidence uploaded".into()));
251	                                            }
252	                                            Err(e) => set_status.set(Some(format!("Upload error: {}", e.message))),
253	                                        }
254	                                    });
255	                                }
256	                                #[cfg(not(target_arch = "wasm32"))]
257	                                {
258	                                    let _ = (oid, file, set_evidence_files);
259	                                    set_status.set(Some("Upload only available in browser".into()));
260	                                }
261	                                        }
262	                                    }
263	                                }
264	                            />
265	                            {move || {
