1	//! Outcome / IP Leptos pages — list, multi-step register, side-by-side compare.
2	
3	use leptos::*;
4	
5	pub mod register;
6	pub mod compare;
7	
8	use crate::api::outcomes as out_api;
9	use crate::components::layout::{NavTarget, PageShell};
10	
11	#[derive(Clone, Copy, PartialEq, Eq)]
12	pub enum OutcomeTab {
13	    List,
14	    Register,
15	    Compare,
16	}
17	
18	#[component]
19	pub fn OutcomesPage() -> impl IntoView {
20	    let (tab, set_tab) = create_signal(OutcomeTab::List);
21	    let outcomes = create_resource(|| (), |_| async move { out_api::list_outcomes().await });
22	
23	    view! {
24	        <PageShell
25	            active=NavTarget::Outcomes
26	            title="Outcome / IP Registration"
27	            subtitle="Register papers, patents, competitions, and software copyrights"
28	        >
29	            <div class="sv-page-header">
30	                <h1 class="sv-page-title">"Outcome / IP Registration"</h1>
31	                <p class="sv-page-subtitle">"Register papers, patents, competition results, and software copyrights with full provenance."</p>
32	            </div>
33	
34	            <div class="sv-tabs">
35	                {tab_button("My Outcomes", OutcomeTab::List, tab, set_tab)}
36	                {tab_button("Register New", OutcomeTab::Register, tab, set_tab)}
37	                {tab_button("Compare", OutcomeTab::Compare, tab, set_tab)}
38	            </div>
39	
40	            {move || match tab.get() {
41	                OutcomeTab::List => view! {
42	                    <div class="sv-card">
43	                        <Suspense fallback=|| view! { <div class="sv-skeleton" style="height:160px;"></div> }>
44	                            {move || outcomes.get().map(|res| match res {
45	                                Ok(rows) if rows.is_empty() => view! {
46	                                    <div style="text-align:center;color:#A0A0B0;padding:32px;">
47	                                        "No outcomes registered yet — switch to the Register tab to add one."
48	                                    </div>
49	                                }.into_view(),
50	                                Ok(rows) => view! {
51	                                    <table class="sv-table">
52	                                        <thead>
53	                                            <tr>
54	                                                <th>"Title"</th>
55	                                                <th>"Type"</th>
56	                                                <th>"Status"</th>
57	                                                <th>"Created"</th>
58	                                            </tr>
59	                                        </thead>
60	                                        <tbody>
61	                                            {rows.into_iter().map(|o| view! {
62	                                                <tr>
63	                                                    <td>{o.title}</td>
64	                                                    <td><span class="sv-badge sv-badge-info">{o.r#type}</span></td>
65	                                                    <td>{render_status_badge(&o.status)}</td>
66	                                                    <td style="color:#A0A0B0;font-size:11px;">{o.created_at}</td>
67	                                                </tr>
68	                                            }).collect_view()}
69	                                        </tbody>
70	                                    </table>
71	                                }.into_view(),
72	                                Err(e) => view! { <div class="sv-error">{format!("Failed: {}", e.message)}</div> }.into_view(),
73	                            })}
74	                        </Suspense>
75	                    </div>
76	                }.into_view(),
77	                OutcomeTab::Register => view! { <register::RegisterOutcome /> }.into_view(),
78	                OutcomeTab::Compare => view! { <compare::CompareOutcomes /> }.into_view(),
79	            }}
80	        </PageShell>
81	    }
82	}
83	
84	fn render_status_badge(status: &str) -> View {
85	    let class = match status {
86	        "approved" => "sv-badge sv-badge-success",
87	        "rejected" => "sv-badge sv-badge-danger",
88	        "submitted" => "sv-badge sv-badge-warning",
89	        _ => "sv-badge sv-badge-info",
90	    };
91	    view! { <span class=class>{status.to_string()}</span> }.into_view()
92	}
93	
94	fn tab_button(
95	    label: &'static str,
96	    this_tab: OutcomeTab,
97	    current: ReadSignal<OutcomeTab>,
98	    setter: WriteSignal<OutcomeTab>,
99	) -> impl IntoView {
100	    view! {
101	        <button
102	            class=move || if current.get() == this_tab { "sv-tab active" } else { "sv-tab" }
103	            on:click=move |_| setter.set(this_tab)
104	        >
105	            {label}
106	        </button>
107	    }
108	}
